member.remarks:
When you use this attribute, Sprite Editor Window will only make the module available for selection if ISpriteEditorDataProvider.HasDataProvider returns true for all the data providers the module needs.

             using UnityEditor.U2D;
             using UnityEngine;

             [RequireSpriteDataProvider(typeof(ISpriteOutlineDataProvider), typeof(ITextureDataProvider))]
             public class MySpriteEditorCustomModule : SpriteEditorModuleBase
             {
                 public override string moduleName
                 {
                     get { return "MySpriteEditorCustomModule"; }
                 }
                 public override bool ApplyRevert(bool apply)
                 {
                     return true;
                 }
                 public override bool CanBeActivated()
                 {
                     return true;
                 }
                 public override void DoMainGUI() { }
                 public override void DoToolbarGUI(Rect drawArea) { }
                 public override void OnModuleActivate()
                 {
                     var outlineProvider = spriteEditor.GetDataProvider<ISpriteOutlineDataProvider>();
                     var spriteRects = spriteEditor.GetDataProvider<ISpriteEditorDataProvider>().GetSpriteRects();
                     foreach (var spriteRect in spriteRects)
                     {
                         // Access outline data
                         Debug.Log(outlineProvider.GetOutlines(spriteRect.spriteID));
                     }
                 }
                 public override void OnModuleDeactivate() { }
                 public override void DoPostGUI() { }
             }

Use this interface to edit Sprite data.

            using UnityEditor;
            using UnityEditor.U2D.Sprites;
            using UnityEngine;

            public class PivotUpdater : AssetPostprocessor
            {
                private void OnPreprocessTexture()
                {
                    var factory = new SpriteDataProviderFactories();
                    factory.Init();
                    var dataProvider = factory.GetSpriteEditorDataProviderFromObject(assetImporter);
                    dataProvider.InitSpriteEditorDataProvider();

                    SetPivot(dataProvider, new Vector2(0.5f, 0.5f));

                    dataProvider.Apply();
                }

                static void SetPivot(ISpriteEditorDataProvider dataProvider, Vector2 pivot)
                {
                    var spriteRects = dataProvider.GetSpriteRects();
                    foreach (var rect in spriteRects)
                    {
                        rect.pivot = pivot;
                        rect.alignment = SpriteAlignment.Custom;
                    }
                    dataProvider.SetSpriteRects(spriteRects);
                }
            }
